import{_ as e,o as n,c as a,ae as o}from"./chunks/framework.Czhw_PXq.js";const b=JSON.parse('{"title":"工程思考｜Vibe Coding：不是AI写代码，是你在指挥一个工程系统","description":"","frontmatter":{},"headers":[],"relativePath":"thinking/vibe-coding-engineering-system.md","filePath":"thinking/vibe-coding-engineering-system.md"}'),t={name:"thinking/vibe-coding-engineering-system.md"};function r(l,i,p,s,g,d){return n(),a("div",null,[...i[0]||(i[0]=[o('<h1 id="工程思考-vibe-coding-不是ai写代码-是你在指挥一个工程系统" tabindex="-1">工程思考｜Vibe Coding：不是AI写代码，是你在指挥一个工程系统 <a class="header-anchor" href="#工程思考-vibe-coding-不是ai写代码-是你在指挥一个工程系统" aria-label="Permalink to &quot;工程思考｜Vibe Coding：不是AI写代码，是你在指挥一个工程系统&quot;">​</a></h1><p>做项目时长出来的想法和教训。Vibe Coding 是我目前在折腾的方向。</p><hr><p>这段时间一直在实践 Vibe Coding，从环境搭起，到跑通第一个 App，再到把测试、CI/CD、Subagent 协作全部串起来。越做越清醒一个事实：</p><p><strong>Vibe Coding 从来不是“让AI帮你偷懒”，而是一套完整的、小型的、现代工程体系。</strong></p><p>你以为你在写代码，其实你在搭建一个<strong>能自我检查、能持续迭代、能稳定交付</strong>的小系统。</p><h2 id="一、我们真的在教ai写代码吗-不是。" tabindex="-1">一、我们真的在教AI写代码吗？不是。 <a class="header-anchor" href="#一、我们真的在教ai写代码吗-不是。" aria-label="Permalink to &quot;一、我们真的在教AI写代码吗？不是。&quot;">​</a></h2><p>大多数人对 AI 编程的理解停留在： 我说需求 → AI 出代码 → 复制粘贴 → 跑起来。</p><p>这不是 Vibe Coding。 这叫<strong>一次性代码玩具</strong>。</p><p>真正的 Vibe 是： 你定义规则 → AI 按规则执行 → 系统自动校验 → 不达标不让提交 → 自动保证质量。</p><p>它的核心不是“快”， 是<strong>可控</strong>。</p><h2 id="二、工程上最值钱的-从来不是功能-是-不崩溃" tabindex="-1">二、工程上最值钱的，从来不是功能，是“不崩溃” <a class="header-anchor" href="#二、工程上最值钱的-从来不是功能-是-不崩溃" aria-label="Permalink to &quot;二、工程上最值钱的，从来不是功能，是“不崩溃”&quot;">​</a></h2><p>做项目久了都会懂： 能写出功能不厉害， 能保证<strong>改一百次都不崩</strong>，才厉害。</p><p>Vibe Coding 这套训练营最有价值的，不是教你做任务管理、加番茄钟，而是把四件事焊死在流程里：</p><ol><li>日志：发生什么，留痕可查</li><li>测试：改之前先考一遍</li><li>回归：新加功能不拆家</li><li>门禁：烂代码不让提交</li></ol><p>这四件事，就是<strong>小型工程的全部底线</strong>。</p><p>AI 可以帮你写 90% 的代码， 但守住底线的那个人，只能是你。</p><h2 id="三、ai-时代的开发-本质是-指挥系统" tabindex="-1">三、AI 时代的开发，本质是“指挥系统” <a class="header-anchor" href="#三、ai-时代的开发-本质是-指挥系统" aria-label="Permalink to &quot;三、AI 时代的开发，本质是“指挥系统”&quot;">​</a></h2><p>我越来越有一个体感：</p><p><strong>传统开发：人 → 代码。</strong><strong>AI 开发：人 → 系统 → AI → 代码。</strong></p><p>你不再直接跟代码搏斗。 你在跟一整套系统对话： 提示词、上下文、MCP、Skills、Subagent、测试、门禁、部署。</p><p>你的工作变成：</p><ul><li>设计流程</li><li>制定规则</li><li>分配角色</li><li>守住质量</li><li>接受交付</li></ul><p>这不叫“写代码”。 这叫<strong>指挥一支AI开发小队</strong>。</p><h2 id="四、为什么小项目也要讲工程-因为它会长大" tabindex="-1">四、为什么小项目也要讲工程？因为它会长大 <a class="header-anchor" href="#四、为什么小项目也要讲工程-因为它会长大" aria-label="Permalink to &quot;四、为什么小项目也要讲工程？因为它会长大&quot;">​</a></h2><p>很多人觉得：就一个个人项目，搞什么测试、CI/CD、重构，太折腾。</p><p>但工程能力的本质是： <strong>在它还小的时候，就用对的结构，让它长大不会变形。</strong></p><p>Vibe Coding 教的就是这个： 从第一行代码开始，就按工程标准来。</p><ul><li>目录结构清晰</li><li>数据持久化规范</li><li>接口干净</li><li>测试覆盖</li><li>日志齐全</li><li>提交有门禁</li></ul><p>等你真的要扩展、加人、上线、维护，别人的项目已经烂成泥潭，你的依然能轻松迭代。</p><h2 id="五、写在后面-什么是真正的-ai-能力" tabindex="-1">五、写在后面：什么是真正的“AI 能力” <a class="header-anchor" href="#五、写在后面-什么是真正的-ai-能力" aria-label="Permalink to &quot;五、写在后面：什么是真正的“AI 能力”&quot;">​</a></h2><p>这段实践下来，我越来越明确：</p><p><strong>未来不缺会写代码的人，缺敢让AI写、又能Hold住质量的人。</strong></p><p>AI 负责效率。 你负责：对、稳、准、安全、可维护、可迭代。</p><p>这就是下一代开发者的核心壁垒。</p><p>Vibe Coding 对我来说，不是一套课程。 它是一种<strong>新的工作方式</strong>： 慢一点思考，稳一点落地，用工程压住速度，用AI放大能力。</p><p>不追求完美，先占坑，后面慢慢更新。 这本身就是设计哲学。</p>',37)])])}const c=e(t,[["render",r]]);export{b as __pageData,c as default};
